import React, { useState } from 'react';
import '../css/roundedTextBox.css';
import '../css/basics.css';
import '../css/authentication.css';
import '../css/font.css';
import '../css/checkbox.css';
import InputWithImage from './components/InputWithImage';

const Register = () => {
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [username, setUsername] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  return (
    <div className="authentication_block">
      {/* Left-side image */}
      <div className="authentication_image_block">
        <img
          src="/images/register.png"
          alt="register"
          className="register_image"
        />
      </div>

      {/* Right-side form */}
      <div className="authentication_textboxes_block register_padding_top">
        <header>Sign Up</header>

        <InputWithImage
          icon="/images/icons/first_name.svg"
          alt="first name"
          placeholder="Enter First Name"
          value={firstName}
          onChange={(e) => setFirstName(e.target.value)}
        />

        <InputWithImage
          icon="/images/icons/last_name.svg"
          alt="last name"
          placeholder="Enter Last Name"
          value={lastName}
          onChange={(e) => setLastName(e.target.value)}
        />

        <InputWithImage
          icon="/images/icons/username.svg"
          alt="username"
          placeholder="Enter Username"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
        />

        <InputWithImage
          icon="/images/icons/email.svg"
          alt="email"
          placeholder="Enter Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />

        <InputWithImage
          icon="/images/icons/black_password.svg"
          alt="password"
          placeholder="Enter Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />

        <InputWithImage
          icon="/images/icons/white_password.svg"
          alt="confirm password"
          placeholder="Confirm Password"
          value={confirmPassword}
          onChange={(e) => setConfirmPassword(e.target.value)}
        />

        <div className="horizontal left gap10">
          <input type="checkbox" className="center" />
          <label className="nowrap center margin_top_1 light">
            I agree to all terms
          </label>
        </div>

        <button className="red_button">Register</button>

        <div>
          <label>Already have an account? </label>
          <label className="blue_text">Sign In</label>
        </div>
      </div>
    </div>
  );
};

export default Register;
